      "title": "Special Eurobarometer 460: Attitudes towards the impact of digitisation and automation on daily life",
      "description": "EU-wide survey on public perceptions of digitalisation and automation in everyday life and work, including perceived benefits and risks, skills, employment impacts, and policy considerations.",
      "host": "GESIS",
      "series": "Eurobarometer",
      "topics": ["digitalization", "automation", "policy"]
    },
    {
      "title": "Special Eurobarometer: Attitudes towards robots and artificial intelligence",
      "description": "EU-wide survey examining public attitudes toward robots and AI, including trust, expected benefits and risks, regulation preferences, and areas of application.",
      "host": "GESIS",
      "series": "Eurobarometer",
      "topics": ["artificial intelligence", "technology attitudes", "policy"]
    },
    {
      "title": "Special Eurobarometer: Public perceptions of science, research and innovation",
      "description": "EU-wide survey on public views of science and research, including trust in scientific institutions, awareness of research activities, and expectations about innovation and its governance.",
      "host": "GESIS",
      "series": "Eurobarometer",
      "topics": ["university research", "science policy", "innovation"]
    },
    {
      "title": "The Changing Academic Profession (CAP) International Survey",
      "description": "Comparative survey of university academics focusing on teaching and research roles, career paths, governance, evaluation, and the impact of policy changes in higher education.",
      "host": "GESIS",
      "series": "Academic Profession",
      "topics": ["university", "university policy", "university research"]
    },
    {
      "title": "Academic Profession in Europe (EUROAC) Survey",
      "description": "Survey of academics across European higher education institutions on work conditions, research activities, institutional governance, performance evaluation, and policy environments.",
      "host": "GESIS",
      "series": "Academic Profession",
      "topics": ["university", "university policy", "university research"]
    }
  ]
}
